// // This module takes in 4 input bits and outputs a single bit. It stores the input in a register on the rising edge of the clock, assigns it to a wire, and sets the output to 1 if the wire's value is greater than 5, otherwise 0.
module my_module(
    input clk,
    input [3:0] data_in,
    output reg data_out
);

    reg [3:0] data_reg;
    wire [3:0] data_wire;

    always @(posedge clk) begin
        data_reg <= data_in;
    end

    assign data_wire = data_reg;

    always @(*) begin
        if (data_wire <= 5) begin
            data_out = 1;
        end else begin
            data_out = 0;
        end
    end

endmodule
